from pathlib import Path

game_component = '''
import { useState, useEffect, useCallback } from 'react'
import './SnakeGame.css'

type Position = {
  x: number
  y: number
}

type Direction = 'UP' | 'DOWN' | 'LEFT' | 'RIGHT'

const BOARD_SIZE = 20
const INITIAL_SNAKE: Position[] = [
  { x: 10, y: 10 },
  { x: 9, y: 10 },
  { x: 8, y: 10 },
]
const INITIAL_DIRECTION: Direction = 'RIGHT'
const INITIAL_FOOD: Position = { x: 15, y: 15 }
const GAME_SPEED = 150

function getRandomFood(snake: Position[]): Position {
  let newFood: Position
  do {
    newFood = {
      x: Math.floor(Math.random() * BOARD_SIZE),
      y: Math.floor(Math.random() * BOARD_SIZE),
    }
  } while (snake.some(segment => segment.x === newFood.x && segment.y === newFood.y))
  return newFood
}

export default function SnakeGame() {
  const [snake, setSnake] = useState<Position[]>(INITIAL_SNAKE)
  const [direction, setDirection] = useState<Direction>(INITIAL_DIRECTION)
  const [food, setFood] = useState<Position>(INITIAL_FOOD)
  const [gameOver, setGameOver] = useState(false)
  const [score, setScore] = useState(0)
  const [isPaused, setIsPaused] = useState(false)

  const moveSnake = useCallback(() => {
    if (gameOver || isPaused) return

    setSnake(prevSnake => {
      const head = prevSnake[0]
      const newHead = { ...head }

      switch (direction) {
        case 'UP':
          newHead.y -= 1
          break
        case 'DOWN':
          newHead.y += 1
          break
        case 'LEFT':
          newHead.x -= 1
          break
        case 'RIGHT':
          newHead.x += 1
          break
      }

      // Check collision with walls
      if (
        newHead.x < 0 ||
        newHead.x >= BOARD_SIZE ||
        newHead.y < 0 ||
        newHead.y >= BOARD_SIZE
      ) {
        setGameOver(true)
        return prevSnake
      }

      // Check collision with self
      if (prevSnake.some(segment => segment.x === newHead.x && segment.y === newHead.y)) {
        setGameOver(true)
        return prevSnake
      }

      const newSnake = [newHead, ...prevSnake]

      // Check if food is eaten
      if (newHead.x === food.x && newHead.y === food.y) {
        setScore(prevScore => prevScore + 1)
        setFood(getRandomFood(newSnake))
      } else {
        newSnake.pop()
      }

      return newSnake
    })
  }, [direction, food, gameOver, isPaused])

  useEffect(() => {
    const interval = setInterval(moveSnake, GAME_SPEED)
    return () => clearInterval(interval)
  }, [moveSnake])

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      switch (e.key) {
        case 'ArrowUp':
          if (direction !== 'DOWN') setDirection('UP')
          break
        case 'ArrowDown':
          if (direction !== 'UP') setDirection('DOWN')
          break
        case 'ArrowLeft':
          if (direction !== 'RIGHT') setDirection('LEFT')
          break
        case 'ArrowRight':
          if (direction !== 'LEFT') setDirection('RIGHT')
          break
        case ' ':
          setIsPaused(prev => !prev)
          break
      }
    }

    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [direction])

  const resetGame = () => {
    setSnake(INITIAL_SNAKE)
    setDirection(INITIAL_DIRECTION)
    setFood(INITIAL_FOOD)
    setGameOver(false)
    setScore(0)
    setIsPaused(false)
  }

  return (
    <div className="snake-game-container">
      <h1>Snake Game</h1>
      <div className="score-board">
        <span>Score: {score}</span>
        {isPaused && <span className="paused">PAUSED</span>}
      </div>
      <div className="game-board" style={{ gridTemplateColumns: `repeat(${BOARD_SIZE}, 1fr)` }}>
        {Array.from({ length: BOARD_SIZE * BOARD_SIZE }).map((_, index) => {
          const x = index % BOARD_SIZE
          const y = Math.floor(index / BOARD_SIZE)
          const isSnakeHead = snake[0].x === x && snake[0].y === y
          const isSnakeBody = snake.slice(1).some(segment => segment.x === x && segment.y === y)
          const isFood = food.x === x && food.y === y

          return (
            <div
              key={index}
              className={`cell ${isSnakeHead ? 'snake-head' : ''} ${isSnakeBody ? 'snake-body' : ''} ${isFood ? 'food' : ''}`}
            />
          )
        })}
      </div>
      {gameOver && (
        <div className="game-over">
          <h2>Game Over!</h2>
          <p>Your score: {score}</p>
          <button onClick={resetGame}>Play Again</button>
        </div>
      )}
      <div className="controls">
        <p>Use arrow keys to move</p>
        <p>Press spacebar to pause/resume</p>
      </div>
    </div>
  )
}
'''

