    const { result } = renderHook(() => useSnakeGame())

    // Move the snake to the food position
    for (let i = 0; i < 5; i++) {
      await act(async () => {
        vi.advanceTimersByTime(150)
      })
    }

    expect(result.current.snake).toHaveLength(4)
    expect(result.current.score).toBe(1)
  })

  it('should end the game when hitting a wall', async () => {
    const { result } = renderHook(() => useSnakeGame())

    // Move the snake up until it hits the wall
    act(() => {
      result.current.changeDirection('UP')
    })

    for (let i = 0; i < 11; i++) {
      await act(async () => {
        vi.advanceTimersByTime(150)
      })
    }

    expect(result.current.gameOver).toBe(true)
  })

